export function benchmark<T extends (...args: any[]) => any>(this: any, fn: T) {
  const stats = {
    count: 0,
    time: 0,
  };
  const _fn = (...args: any[]) => {
    stats.count++;
    const now1 = performance.now();
    const ret = fn.call(this, ...args);
    const now2 = performance.now();
    stats.time += now2 - now1;
    return ret;
  };
  return {
    fn: _fn as T,
    stats,
  };
}
